#!/usr/bin/env bash
set -euo pipefail

DOTS_DIR="$HOME/.dots"
TARGET="$HOME"
OS="$(uname)"

usage() {
    cat <<EOF
Usage: dots-link <command> [args]

Commands:
  apply              Create symlinks from dotfiles repo into \$HOME
  remove             Remove all managed symlinks
  diff               Dry-run: show what apply would do
  status             Show link health (ok, broken, missing)
  ignore <pattern>   Add a pattern to the OS-specific stow ignore file
  unignore <pattern> Remove a pattern from the OS-specific stow ignore file
  (no command)       Same as apply
EOF
}

# Merge base + OS-specific ignore into .stow-local-ignore
_merge_ignore() {
    local base="$DOTS_DIR/.stow-base-ignore"
    local os_ignore="$DOTS_DIR/.stow-${OS}-ignore"
    local out="$DOTS_DIR/.stow-local-ignore"

    > "$out"
    [ -f "$base" ]      && cat "$base" >> "$out"
    echo >> "$out"
    [ -f "$os_ignore" ] && cat "$os_ignore" >> "$out"
}

cmd_apply() {
    _merge_ignore
    cd "$DOTS_DIR" && stow -v -t "$TARGET" .
}

cmd_remove() {
    _merge_ignore
    cd "$DOTS_DIR" && stow -D -v -t "$TARGET" .
}

cmd_diff() {
    _merge_ignore
    cd "$DOTS_DIR" && stow --no -v -t "$TARGET" .
}

cmd_status() {
    local ok=0 broken=0
    echo "Managed symlinks:"
    echo

    check_link() {
        local display="$1" path="$2"
        if [ -L "$path" ]; then
            local target; target="$(readlink "$path")"
            if [[ "$target" == .dots/* ]] || [[ "$target" == ../.dots/* ]]; then
                if [ -e "$path" ]; then
                    echo "  ✓ $display"
                    ok=$(( ok + 1 ))
                else
                    echo "  ✗ $display  (broken -> $target)"
                    broken=$(( broken + 1 ))
                fi
            fi
        fi
    }

    for item in "$TARGET"/.??* "$TARGET"/*; do
        [ -e "$item" ] || continue
        check_link "$(basename "$item")" "$item"
    done

    for item in "$TARGET"/.config/*; do
        [ -e "$item" ] || continue
        check_link ".config/$(basename "$item")" "$item"
    done

    echo
    echo "  ok: $ok   broken: $broken"
}

cmd_ignore() {
    [ -z "${1:-}" ] && { echo "Usage: dots-link ignore <pattern>"; exit 1; }
    echo "$1" >> "$DOTS_DIR/.stow-${OS}-ignore"
    echo "Added '$1' to .stow-${OS}-ignore"
}

cmd_unignore() {
    [ -z "${1:-}" ] && { echo "Usage: dots-link unignore <pattern>"; exit 1; }
    sed -i '' "/^$(printf '%s' "$1" | sed 's/[.[\*^$]/\\&/g')$/d" "$DOTS_DIR/.stow-${OS}-ignore"
    echo "Removed '$1' from .stow-${OS}-ignore"
}

case "${1:-apply}" in
    apply)       cmd_apply ;;
    remove)      cmd_remove ;;
    diff)        cmd_diff ;;
    status)      cmd_status ;;
    ignore)      shift; cmd_ignore "$@" ;;
    unignore)    shift; cmd_unignore "$@" ;;
    -h|--help)   usage ;;
    *)           usage; exit 1 ;;
esac
---
#!/bin/sh
export WEBKIT_DISABLE_DMABUF_RENDERER=1
exec /usr/bin/rquickshare "$@"

